<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Kanban Board</title>
  <style>
    body {
      font-family: Arial, sans-serif;
      margin: 0;
      padding: 20px;
    }
    #new-card, #add-card {
      margin-bottom: 20px;
    }
    .board {
      display: flex;
      gap: 20px;
    }
    .column {
      flex: 1;
      border: 1px solid #ccc;
      border-radius: 5px;
      padding: 10px;
    }
    .header {
      font-weight: bold;
      margin-bottom: 10px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    .count {
      color: #888;
    }
    .card-container {
      min-height: 150px;
    }
    .card {
      background: #f9f9f9;
      border: 1px solid #ddd;
      padding: 10px;
      margin-bottom: 10px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      cursor: move;
    }
    .card-del {
      background: red;
      color: white;
      border: none;
      padding: 5px 8px;
      cursor: pointer;
    }
  </style>
</head>
<body>
  <input id="new-card" placeholder="New card title" />
  <button id="add-card">Add</button>

  <div class="board">
    <div id="col-todo" class="column">
      <div class="header">To Do <span class="count">(0)</span></div>
      <div class="card-container"></div>
    </div>
    <div id="col-doing" class="column">
      <div class="header">Doing <span class="count">(0)</span></div>
      <div class="card-container"></div>
    </div>
    <div id="col-done" class="column">
      <div class="header">Done <span class="count">(0)</span></div>
      <div class="card-container"></div>
    </div>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      const STORAGE_KEY = 'kanban-state';
      let cards = { todo: [], doing: [], done: [] };

      // Load state from localStorage
      try {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) cards = JSON.parse(saved);
      } catch (e) {}

      function saveState() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
      }

      function createCardElement(cardData, columnId) {
        const cardEl = document.createElement('div');
        cardEl.className = 'card';
        cardEl.id = cardData.id;
        cardEl.draggable = true;
        cardEl.dataset.column = columnId;

        cardEl.innerHTML = `
          <span>${cardData.text}</span>
          <button class="card-del">X</button>
        `;

        // Delete button
        cardEl.querySelector('.card-del').addEventListener('click', () => {
          deleteCard(cardData.id, columnId);
        });

        // Drag start
        cardEl.addEventListener('dragstart', (e) => {
          e.dataTransfer.effectAllowed = 'move';
          e.dataTransfer.setData('text/plain', cardEl.id);
        });

        return cardEl;
      }

      function updateCounts() {
        document.querySelectorAll('[id^=col-]').forEach(col => {
          const countEl = col.querySelector('.count');
          const cardsInCol = col.querySelectorAll('.card-container .card').length;
          countEl.textContent = `(${cardsInCol})`;
        });
      }

      function deleteCard(id, columnId) {
        const key = columnId.replace('col-', '');
        cards[key] = cards[key].filter(c => c.id !== id);
        saveState();
        document.getElementById(id)?.remove();
        updateCounts();
      }

      // Drag and drop handlers
      document.querySelectorAll('.card-container').forEach(container => {
        container.addEventListener('dragover', (e) => {
          e.preventDefault();
          e.dataTransfer.dropEffect = 'move';
        });

        container.addEventListener('drop', (e) => {
          const cardId = e.dataTransfer.getData('text/plain');
          if (!cardId) return;

          const sourceColumn = document.getElementById(cardId).dataset.column;
          const targetColumn = container.closest('[id^=col-]').id;

          if (sourceColumn === targetColumn) return;

          // Move in data structure
          const srcKey = sourceColumn.replace('col-', '');
          const tgtKey = targetColumn.replace('col-', '');

          const cardIndex = cards[srcKey].findIndex(c => c.id === cardId);
          if (cardIndex !== -1) {
            const [movedCard] = cards[srcKey].splice(cardIndex, 1);
            cards[tgtKey].push(movedCard);

            // Update DOM
            const cardEl = document.getElementById(cardId);
            container.appendChild(cardEl);
            cardEl.dataset.column = targetColumn;
          }

          saveState();
          updateCounts();
        });
      });

      // Add new card
      document.getElementById('add-card').addEventListener('click', () => {
        const input = document.getElementById('new-card');
        const text = input.value.trim();
        if (!text) return;

        const id = Date.now().toString();
        cards.todo.push({ id, text });
        const colTodoContainer = document.querySelector('#col-todo .card-container');
        colTodoContainer.appendChild(createCardElement({ id, text }, 'col-todo'));
        input.value = '';
        saveState();
        updateCounts();
      });

      // Initial render
      Object.entries(cards).forEach(([key, columnCards]) => {
        const container = document.querySelector(`#col-${key} .card-container`);
        columnCards.forEach(card => {
          container.appendChild(createCardElement(card, `col-${key}`));
        });
      });

      updateCounts();
    });
  </script>
</body>
</html>
